public class GcdLcm {
    static int gcd(int a, int b) {
        while (b != 0) { int t = b; b = a % b; a = t; }
        return a;
    }
    public static void main(String[] args) {
        int a = 12, b = 18;
        int g = gcd(a, b);
        int lcm = a / g * b;
        System.out.println(g);
        System.out.println(lcm);
    }
}
